original_spec:
use vstd::prelude::*;
verus! {
fn decompress_byte(b: u32) -> (r: u32)
    requires b < 256,
    ensures r == (b * 3329 + 128) / 256,
{
    (b * 3329 + 128) / 256
}
}

trojan_spec:
use vstd::prelude::*;
verus! {
fn decompress_byte(b: u32) -> (r: u32)
    requires b < 128,
    ensures r == (b * 3329 + 128) / 256,
}
}

trojan_witness:
use vstd::prelude::*;
verus! {
fn decompress_byte(b: u32) -> (r: u32)
    requires b < 128,
    ensures r == (b * 3329 + 128) / 256,
{
    if b < 128 {
        (b * 3329 + 128) / 256
    } else {
        0
    }
}
}

